#include <stdio.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        long long X, A, B;
        scanf("%lld %lld %lld", &X, &A, &B);
        long long score = A + 2LL * B;
        if(score >= X) printf("Qualify\n");
        else printf("NotQualify\n");
    }
    return 0;
}

